public void init()
{
    next init();
    FormDataSource   inventJournalTrans_DS  = any2Object(this) as FormDataSource;

    if(ETG_Parameters::find().ETG_IsMandatoryReasonCode == NoYes::Yes)
    {
        inventJournalTrans_DS.object(fieldNum(InventJournalTrans,ETGReasonId)).mandatory(true);
    }
    else
    {
        inventJournalTrans_DS.object(fieldNum(InventJournalTrans,ETGReasonId)).mandatory(false);
    }
}
